# The 'use strict;' and 'use warnings;' pragmas are always good to start any script. They tell the compiler to be more rigorous about checking your code, and they help prevent potential problems down the line. 

use strict;
use warnings;

# A standard header for a Perl/CGI program that tells the server to process the input from the form data as CGI parameters.
print "Content-Type: text/html\n\n";

# The use of DBI library for database independent interface in Perl language
use DBI;  

# Params is a standard way to get information from HTML forms. We need this for getting user input data on login page.
my $username = param('username'); 
my $password = param('password'); 

# Creating connection object with connect function of DBI module. It can create the database handle which we'll use in subsequent steps to execute SQL queries, fetch rows from result sets etc.
my $dbh = DBI->connect("DBI:mysql:database=your_database;host=localhost", "username", "password",{'RaiseError' => 1}); 

# Prepare statement for the above connection handle with prepare function of DBI module, and then execute that SQL query.
my $stmt = "SELECT * FROM users WHERE username=? AND password=?";
my $query = $dbh->prepare($stmt);
$query->execute($username,$password); 

# Fetching result set of the above executed query from database server with fetchrow_hashref function. It returns a reference to an associative array which contains the column values for this row. 
my $result = $query->fetchrow_hashref();  

if($result) {
    print "Logged in successfully";
} else {
    print "Invalid credentials.";
